INSERT INTO `email_sms_templates` VALUES (1,'PASS_RESET_CODE','Password Reset','Password Reset','<div>We have received a request to reset the password for your account on <b>{{time}} .<br></b></div><div>Requested From IP: <b>{{ip}}</b> using <b>{{browser}}</b> on <b>{{operating_system}} </b>.</div><div><br></div><br><div><div><div>Your account recovery code is:&nbsp;&nbsp; <font size=\"6\"><b>{{code}}</b></font></div><div><br></div></div></div><div><br></div><div><font size=\"4\" color=\"#CC0000\">If you do not wish to reset your password, please disregard this message.&nbsp;</font><br></div><br>','Your account recovery code is: {{code}}',' {\"code\":\"Password Reset Code\",\"ip\":\"IP of User\",\"browser\":\"Browser of User\",\"operating_system\":\"Operating System of User\",\"time\":\"Request Time\"}',1,1,'2019-09-24 23:04:05','2021-01-06 00:49:06'),(2,'PASS_RESET_DONE','Password Reset Confirmation','You password have been reset','<div><p>\r\n    You have successfully reset your password.</p><p>You changed from&nbsp; IP: <b>{{ip}}</b> using <b>{{browser}}</b> on <b>{{operating_system}}&nbsp;</b> on <b>{{time}}</b></p><p><b><br></b></p><p><font color=\"#FF0000\"><b>If you did not changed that, Please contact with us as soon as possible.</b></font><br></p></div>','Your password has been changed successfully','{\"ip\":\"IP of User\",\"browser\":\"Browser of User\",\"operating_system\":\"Operating System of User\",\"time\":\"Request Time\"}',1,1,'2019-09-24 23:04:05','2024-11-05 19:58:17'),(3,'EVER_CODE','Email Verification','Verify your email address','<div><br></div><div>Email Verification. <br></div><div>Please use below code to verify your email address.<br></div><div><br></div><div>Your email verification code is:<font size=\"6\"><b> {{code}}</b></font></div>','Your email verification code is: {{code}}','{\"code\":\"Verification code\"}',1,1,'2019-09-24 23:04:05','2024-11-05 19:53:32'),(4,'SVER_CODE','SMS Verification ','Please verify your phone','Your phone veri