--
-- Table structure for table `general_settings`
--

DROP TABLE IF EXISTS `general_settings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `general_settings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `sitename` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cur_text` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'currency text',
  `cur_sym` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'currency symbol',
  `email_from` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email_template` text COLLATE utf8mb4_unicode_ci,
  `sms_api` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `base_color` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `secondary_color` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mail_config` text COLLATE utf8mb4_unicode_ci COMMENT 'email configuration',
  `sms_config` text COLLATE utf8mb4_unicode_ci,
  `ev` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'email verification, 0 - dont check, 1 - check',
  `en` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'email notification, 0 - dont send, 1 - send',
  `sv` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'sms verication, 0 - dont check, 1 - check',
  `sn` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'sms notification, 0 - dont send, 1 - send',
  `force_ssl` tinyint(1) NOT NULL DEFAULT '0',
  `min_compound` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `deposit_commission` varchar(3) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `invest_commission` varchar(3) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `invest_return_commission` varchar(3) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `agree` tinyint(1) NOT NULL DEFAULT '0',
  `registration` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0: Off	, 1: On',
  `active_template` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sys_version` text COLLATE utf8mb4_unicode_ci,
  `swap` text COLLATE utf8mb4_unicode_ci,
  `cardfee` int DEFAULT NULL,
  `transferfee` int DEFAULT NULL,
  `local_transfer_enabled` tinyint(1) NOT NULL DEFAULT '0',
  `local_transfer_require_pin` tinyint(1) NOT NULL DEFAULT '1',
  `local_transfer_min` decimal(18,2) DEFAULT NULL,
  `local_transfer_max` decimal(18,2) DEFAULT NULL,
  `local_transfer_directory_provider` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `local_transfer_resolve_order` json DEFAULT NULL,
  `local_transfer_transfer_order` json DEFAULT NULL,
  `local_transfer_settings` longtext COLLATE utf8mb4_unicode_ci,
  `kyc_subscription_enabled` tinyint(1) NOT NULL DEFAULT '0',
  `bill_payment_enabled` tinyint(1) NOT NULL DEFAULT '1',
  `bill_payment_default_provider` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'budpay',
  `bill_payment_service_providers` json DEFAULT NULL,
  `bill_payment_settings` json DEFAULT NULL,
  `bill_payment_auto_sync_enabled` tinyint(1) NOT NULL DEFAULT '1',
  `bill_payment_auto_sync_hours` smallint unsigned NOT NULL DEFAULT '8',
  `bill_payment_catalog_last_synced_at` timestamp NULL DEFAULT NULL,
  `kyc_subscription_settings` longtext COLLATE utf8mb4_unicode_ci,
  `identity_verification_settings` longtext COLLATE utf8mb4_unicode_ci,
  `deposit_checkout_settings` longtext COLLATE utf8mb4_unicode_ci,
  `virtual_card_settings` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

