--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `psid` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `firstname` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `middlename` varchar(35) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lastname` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `username` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `account_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paystackcode` mediumtext COLLATE utf8mb4_unicode_ci,
  `email` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `country_code` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mobile` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `whatsapp_phone` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `NIN` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `BVN` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mother_maiden_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_additional_data` json DEFAULT NULL,
  `is_kyc_upgraded` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'User has upgraded to access KYC services',
  `kyc_plan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'kyc_basic, kyc_premium, kyc_enterprise',
  `kyc_pending_plan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_upgrade_date` datetime DEFAULT NULL COMMENT 'Date when user upgraded KYC services',
  `kyc_expiry_date` datetime DEFAULT NULL COMMENT 'When KYC services expire (null = lifetime)',
  `kyc_monthly_limit` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Monthly spending limit for KYC services',
  `kyc_monthly_spent` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Amount spent this month on KYC',
  `kyc_paystack_reference` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_paystack_plan_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_paystack_subscription_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_paystack_email_token` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_subscription_status` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_subscription_channel` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc_subscription_started_at` datetime DEFAULT NULL,
  `kyc_subscription_next_payment_at` datetime DEFAULT NULL,
  `kyc_subscription_cancelled_at` datetime DEFAULT NULL,
  `kyc_subscription_last_payment_at` datetime DEFAULT NULL,
  `kyc_subscription_last_invoice_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `employment` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `income` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dob` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ref_by` int unsigned NOT NULL DEFAULT '0',
  `balance` decimal(28,2) NOT NULL DEFAULT '0.00',
  `usdbalance` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0.00',
  `compound` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0',
  `ref_bonus` varchar(9) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0',
  `usertype` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '1',
  `invest_return` varchar(9) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0',
  `invest_returnusd` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `pin` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pin_state` int NOT NULL DEFAULT '0',
  `image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `address` text COLLATE utf8mb4_unicode_ci COMMENT 'contains full address',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '0: banned, 1: active',
  `pslinked` tinyint NOT NULL DEFAULT '0',
  `psverified` tinyint NOT NULL DEFAULT '0',
  `ussd` int NOT NULL DEFAULT '0',
  `ev` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0: email unverified, 1: email verified',
  `sv` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0: sms unverified, 1: sms verified',
  `ver_code` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'stores verification code',
  `ver_code_send_at` datetime DEFAULT NULL COMMENT 'verification send time',
  `ts` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0: 2fa off, 1: 2fa on',
  `tv` tinyint(1) NOT NULL DEFAULT '1' COMMENT '0: 2fa unverified, 1: 2fa verified',
  `tsc` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kyc` int NOT NULL DEFAULT '0',
  `bN1` text COLLATE utf8mb4_unicode_ci,
  `bN2` text COLLATE utf8mb4_unicode_ci,
  `bN3` text COLLATE utf8mb4_unicode_ci,
  `aN1` text COLLATE utf8mb4_unicode_ci,
  `aN2` text COLLATE utf8mb4_unicode_ci,
  `aN3` text COLLATE utf8mb4_unicode_ci,
  `aNo1` text COLLATE utf8mb4_unicode_ci,
  `aNo2` text COLLATE utf8mb4_unicode_ci,
  `aNo3` text COLLATE utf8mb4_unicode_ci,
  `aNid1` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `aNid2` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `budpay_customer_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `budpay_customer_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `budpay_virtual_account_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `budpay_virtual_account_reference` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `budpay_linked` tinyint(1) NOT NULL DEFAULT '0',
  `budpay_verified` tinyint unsigned NOT NULL DEFAULT '0',
  `kora_account_reference` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kora_virtual_account_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kora_bank_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kora_linked` tinyint(1) NOT NULL DEFAULT '0',
  `kora_verified` tinyint unsigned NOT NULL DEFAULT '0',
  `squad_customer_reference` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `squad_customer_status` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `identity_source` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `identity_locked_at` datetime DEFAULT NULL,
  `identity_verified_at` datetime DEFAULT NULL,
  `identity_payload` longtext COLLATE utf8mb4_unicode_ci,
  `identity_date_of_birth` date DEFAULT NULL,
  `identity_gender` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `identity_middle_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_verification_channel` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_verification_reference` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_verification_requested_at` datetime DEFAULT NULL,
  `phone_verified_externally_at` datetime DEFAULT NULL,
  `aNid3` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `remember_token` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `monnify_token` text COLLATE utf8mb4_unicode_ci NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`,`email`),
  UNIQUE KEY `basename` (`firstname`,`lastname`)
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

